/**
 * HUDPanel — Always-visible HUD overlay for local map and world map.
 * Shows in-game time, party gold, ration points, and a compass rose.
 * Updates every second via setInterval.
 * Uses pointer-events: none so it never blocks canvas input.
 *
 * @module HUDPanel
 */

import DebugLog from '../debug/DebugLog.js';
import WorldState from '../world/WorldState.js';

// ─── Compass directions ───────────────────────────────────────────────────────

const COMPASS_LABELS = ['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW'];

// ─── HUDPanel ─────────────────────────────────────────────────────────────────

class HUDPanel {
  constructor() {
    /** @type {HTMLElement|null} Root HUD container */
    this._el = null;

    /** @type {number|null} setInterval ID */
    this._intervalId = null;

    /** @type {boolean} Whether the HUD is currently mounted */
    this._active = false;

    /** @type {Function|null} Reference to TimeSystem.formatTime for display */
    this._formatTime = null;

    /** @type {Function|null} Reference to TimeSystem.isNight */
    this._isNight = null;

    /** @type {number} Compass heading degrees (updated externally if desired) */
    this._heading = 0;
  }

  // ─── Public API ──────────────────────────────────────────────────────────────

  /**
   * Mount and start the HUD.
   * Safe to call multiple times — destroys previous instance first.
   *
   * @param {object} [options]
   * @param {Function} [options.formatTime] — Override TimeSystem.formatTime
   * @param {Function} [options.isNight] — Override TimeSystem.isNight
   */
  init(options = {}) {
    // Destroy any existing HUD
    this.destroy();

    this._formatTime = options.formatTime ?? this._getTimeFn('formatTime');
    this._isNight    = options.isNight    ?? this._getTimeFn('isNight');

    this._buildDOM();
    this.update();

    // Refresh every 1 second
    this._intervalId = setInterval(() => this.update(), 1000);
    this._active = true;

    DebugLog.info('[debug] HUDPanel initialized');
  }

  /**
   * Force-refresh the displayed values.
   * Called automatically by the interval, but can also be called externally
   * after a state change (e.g., gold changes after a purchase).
   */
  update() {
    if (!this._el) return;

    const timeEl   = this._el.querySelector('#hud-time');
    const goldEl   = this._el.querySelector('#hud-gold');
    const rationsEl = this._el.querySelector('#hud-rations');
    const nightEl  = this._el.querySelector('#hud-night-indicator');

    const timeStr = this._getFormattedTime();
    const isNight = this._checkIsNight();
    const gold    = WorldState.partyGold ?? 0;
    const rations = WorldState.rationPoints ?? 0;

    if (timeEl)    timeEl.textContent = timeStr;
    if (goldEl)    goldEl.textContent = `${gold}g`;
    if (rationsEl) rationsEl.textContent = `${rations} rations`;

    // Night indicator — subtle pulse when night
    if (nightEl) {
      nightEl.style.display = isNight ? 'inline-block' : 'none';
    }

    // Update night dimness class on body for scene-level darkness
    document.body.classList.toggle('hud-night-mode', isNight);
  }

  /**
   * Remove the HUD from the DOM and stop the update loop.
   */
  destroy() {
    if (this._intervalId != null) {
      clearInterval(this._intervalId);
      this._intervalId = null;
    }

    if (this._el) {
      this._el.remove();
      this._el = null;
    }

    document.body.classList.remove('hud-night-mode');

    this._active = false;
    DebugLog.info('[debug] HUDPanel destroyed');
  }

  /**
   * Update the compass heading (optional — call from camera/movement system).
   * @param {number} degrees — 0 = North, 90 = East, etc.
   */
  setHeading(degrees) {
    this._heading = degrees % 360;
    const compassNeedle = this._el?.querySelector('.hud-compass-needle');
    if (compassNeedle) {
      compassNeedle.style.transform = `rotate(${this._heading}deg)`;
    }
  }

  // ─── DOM construction ────────────────────────────────────────────────────────

  _buildDOM() {
    // Remove any stale instance
    document.getElementById('hud-panel-root')?.remove();

    const el = document.createElement('div');
    el.id = 'hud-panel-root';
    el.setAttribute('aria-hidden', 'true'); // HUD is decorative, not interactive
    el.innerHTML = `
      <div id="hud-top-bar">

        <!-- Top-left: in-game time -->
        <div id="hud-top-left" class="hud-block hud-time-block">
          <span class="hud-label">Time</span>
          <span id="hud-time" class="hud-value">--:--</span>
          <span id="hud-night-indicator" class="hud-night-star" style="display:none;" title="Night">&#9733;</span>
        </div>

        <!-- Top-center: compass rose -->
        <div id="hud-top-center" class="hud-block hud-compass-block">
          <div class="hud-compass" title="Compass">
            <svg class="hud-compass-svg" viewBox="0 0 40 40" width="36" height="36"
                 aria-hidden="true" focusable="false">
              <!-- Compass ring -->
              <circle cx="20" cy="20" r="18" fill="none" stroke="#5a4a20" stroke-width="1"/>
              <!-- Cardinal tick marks -->
              <line x1="20" y1="3"  x2="20" y2="8"  stroke="#7a6a40" stroke-width="1.5"/>
              <line x1="20" y1="32" x2="20" y2="37" stroke="#5a4a30" stroke-width="1"/>
              <line x1="3"  y1="20" x2="8"  y2="20" stroke="#5a4a30" stroke-width="1"/>
              <line x1="32" y1="20" x2="37" y2="20" stroke="#5a4a30" stroke-width="1"/>
              <!-- N label -->
              <text x="20" y="14" text-anchor="middle" dominant-baseline="middle"
                    font-family="Georgia,serif" font-size="7" fill="#c8a020" font-weight="bold">N</text>
              <!-- Needle (rotated by heading via style) -->
              <g class="hud-compass-needle" style="transform-origin:20px 20px; transform:rotate(0deg)">
                <!-- North pointer (gold) -->
                <polygon points="20,6 17,20 20,18 23,20" fill="#c8a020" opacity="0.9"/>
                <!-- South pointer (dark) -->
                <polygon points="20,34 17,20 20,22 23,20" fill="#3a2a10" opacity="0.7"/>
              </g>
            </svg>
          </div>
        </div>

        <!-- Top-right: gold + rations -->
        <div id="hud-top-right" class="hud-block hud-resources-block">
          <div class="hud-resource-row">
            <span class="hud-resource-icon hud-icon-gold">&#9670;</span>
            <span id="hud-gold" class="hud-value hud-value--gold">0g</span>
          </div>
          <div class="hud-resource-row">
            <span class="hud-resource-icon hud-icon-rations">&#9670;</span>
            <span id="hud-rations" class="hud-value hud-value--rations">0 rations</span>
          </div>
        </div>

      </div>
    `;

    Object.assign(el.style, {
      position:      'fixed',
      inset:         '0',
      zIndex:        'var(--z-hud, 100)',
      pointerEvents: 'none',
      fontFamily:    "'Georgia', 'Times New Roman', serif",
    });

    document.body.appendChild(el);
    this._el = el;

    // Inject HUD styles once
    if (!document.getElementById('hud-panel-styles')) {
      const style = document.createElement('style');
      style.id = 'hud-panel-styles';
      style.textContent = HUD_STYLES;
      document.head.appendChild(style);
    }
  }

  // ─── Time helpers ────────────────────────────────────────────────────────────

  _getFormattedTime() {
    if (this._formatTime) {
      try {
        return this._formatTime();
      } catch (e) {
        DebugLog.warn(`[debug] HUDPanel.formatTime error: ${e.message}`);
      }
    }

    // Try global TimeSystem
    try {
      if (window.__timeSystem?.formatTime) {
        return window.__timeSystem.formatTime();
      }
    } catch (_) {}

    return '06:00';
  }

  _checkIsNight() {
    if (this._isNight) {
      try {
        return this._isNight();
      } catch (_) {}
    }

    try {
      if (window.__timeSystem?.isNight) {
        return window.__timeSystem.isNight();
      }
    } catch (_) {}

    return false;
  }

  /**
   * Try to resolve a method from the global TimeSystem by name.
   * @param {string} methodName
   * @returns {Function|null}
   */
  _getTimeFn(methodName) {
    try {
      if (window.__timeSystem?.[methodName]) {
        return window.__timeSystem[methodName].bind(window.__timeSystem);
      }
    } catch (_) {}
    return null;
  }
}

// ─── Component CSS ────────────────────────────────────────────────────────────

const HUD_STYLES = `
/* ── HUD Panel ──────────────────────────────────────────────────────────── */

#hud-panel-root {
  pointer-events: none;
  user-select: none;
}

#hud-top-bar {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  padding: 8px 12px;
  pointer-events: none;
}

.hud-block {
  background: rgba(10, 7, 3, 0.68);
  border: 1px solid rgba(90, 74, 32, 0.55);
  border-radius: 4px;
  padding: 5px 10px;
  display: flex;
  align-items: center;
  gap: 5px;
  backdrop-filter: blur(2px);
}

/* Time block — explicit flex-shrink: 0 so it never loses its left anchor */
.hud-time-block {
  flex-direction: row;
  gap: 6px;
  flex-shrink: 0;
}

.hud-label {
  font-size: 9px;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  color: #5a4a28;
  flex-shrink: 0;
}

.hud-value {
  font-size: clamp(11px, 1.2vw, 13px);
  color: #d0b870;
  font-weight: bold;
  letter-spacing: 0.04em;
  white-space: nowrap;
}

.hud-night-star {
  color: #6880c0;
  font-size: 10px;
  animation: hud-night-pulse 2.5s ease-in-out infinite;
}

@keyframes hud-night-pulse {
  0%,100% { opacity: 0.6; }
  50%      { opacity: 1.0; }
}

/* Compass */
.hud-compass-block {
  background: rgba(10, 7, 3, 0.65);
  padding: 4px 6px;
}

.hud-compass {
  display: flex;
  align-items: center;
  justify-content: center;
}

.hud-compass-svg {
  display: block;
}

.hud-compass-needle {
  transform-origin: 20px 20px;
  transition: transform 0.3s ease-out;
}

/* Resources block — right-side offset so it never overlaps nav/info buttons
   that world map places in the top-right corner. The margin-right pushes the
   block away from the viewport edge, clearing any 180-220px wide overlay. */
.hud-resources-block {
  flex-direction: column;
  align-items: flex-end;
  gap: 3px;
  padding: 5px 10px;
  margin-right: clamp(0px, 14vw, 200px);
}

.hud-resource-row {
  display: flex;
  align-items: center;
  gap: 5px;
}

.hud-resource-icon {
  font-size: 8px;
  opacity: 0.5;
}

.hud-icon-gold {
  color: #c8a020;
}

.hud-icon-rations {
  color: #7a9a4a;
}

.hud-value--gold {
  color: #d4aa40;
}

.hud-value--rations {
  color: #90b060;
  font-size: clamp(10px, 1.1vw, 12px);
}

/* Night mode — map darkness overlay */
body.hud-night-mode #game-canvas {
  filter: brightness(0.70) saturate(0.75);
  transition: filter 2s ease;
}

body:not(.hud-night-mode) #game-canvas {
  filter: brightness(1.0) saturate(1.0);
  transition: filter 2s ease;
}

/* ── Responsive: hide less-essential elements on small screens ─────────── */

@media (max-width: 767px) {
  #hud-top-bar { padding: 5px 8px; }

  .hud-block { padding: 4px 7px; }

  /* Hide rations text on very small screens, keep gold */
  .hud-value--rations { display: none; }

  /* Shrink compass on mobile */
  .hud-compass-svg { width: 28px; height: 28px; }
}

@media (max-width: 480px) {
  /* Hide compass on smallest screens */
  .hud-compass-block { display: none; }
}
`;

// ─── Singleton export ─────────────────────────────────────────────────────────

export default new HUDPanel();
